export interface Cache {
    /** The cached value for `key`, or `undefined` if missing/expired. Pass `T` for the value type. */
    get<T = unknown>(key: string): Promise<T | undefined>;
    /** Whether a live (non-expired) entry exists. */
    has(key: string): Promise<boolean>;
    /** Store `value` under `key`. */
    set<T>(key: string, value: T, options?: SetOptions): Promise<void>;
    delete(key: string): Promise<void>;
    /** Drop every entry tagged `tag`. */
    invalidateTag(tag: string): Promise<void>;
    clear(): Promise<void>;
    /**
     * Cache-aside: return the cached value, or run `loader`, store the result, and return it. Stampede-safe
     * (concurrent misses for one key share a single `loader` call) and SWR-aware (a stale-but-live value is
     * returned immediately while a deduped background refresh runs). A throwing `loader` is NOT cached.
     */
    wrap<T>(key: string, loader: () => T, options?: WrapOptions): Promise<Awaited<T>>;
}

export interface CacheControlOptions {
    /** Methods whose responses get the header. Default `["GET", "HEAD"]`. */
    readonly methods?: readonly string[];
    /** Predicate over the response status. Default: 2xx only. */
    readonly status?: (status: number) => boolean;
    /** When `true` (default), don't overwrite a `Cache-Control` the handler already set. */
    readonly respectExisting?: boolean;
}

export interface CachedAppLoaderOptions {
    readonly loadApp?: LoadAppForCache;
    readonly fingerprint?: (cwd: string) => Promise<string>;
}

export interface CachedResponse {
    readonly status: number;
    readonly statusText: string;
    readonly headers: readonly [string, string][];
    readonly body: Uint8Array;
    readonly expiresAt: number;
    readonly storedAt: number;
}

export interface CachedResponse {
    /** The rendered document (UTF-8 HTML, fully buffered). */
    readonly body: string;
    readonly status: number;
    /** Response headers to replay (e.g. `content-type`). */
    readonly headers: Readonly<Record<string, string>>;
    /** When this entry was stored, via the injected clock (ms epoch). */
    readonly storedAt: number;
    /** Freshness window (ms): `now - storedAt >= revalidate` ⇒ stale (serve it, regenerate behind it). */
    readonly revalidate: number;
}

export interface CacheOptions {
    /** Storage adapter. Default: a fresh {@link MemoryCache}. */
    readonly store?: CacheStore;
    /** Default TTL (ms) for `set`/`wrap` when none is given. Default 60_000. */
    readonly defaultTtlMs?: number;
    /** Injectable clock (tests). Default `() => Date.now()`. */
    readonly now?: () => number;
    /** Called when a background SWR revalidation throws. Default: `console.error`. */
    readonly onError?: (error: unknown, key: string) => void;
}

export interface CacheOptions {
    readonly store: ResponseCacheStore;
    /** Time to live in milliseconds. */
    readonly ttlMs: number;
    /** Methods cached. Default `["GET", "HEAD"]`. */
    readonly methods?: readonly string[];
    /** Status predicate. Default: `200` only. */
    readonly status?: (status: number) => boolean;
    /** Header names included in the cache key and emitted in `Vary`. */
    readonly vary?: readonly string[];
    /** Custom cache key. Receives the normalized `vary` headers through the request itself. */
    readonly key?: (request: Request) => string;
    /** Maximum response bytes to store. Default `1_000_000`. Larger responses pass through. */
    readonly maxBytes?: number;
    /** Respect request `Cache-Control: no-cache/no-store`. Default `true`. */
    readonly respectRequestCacheControl?: boolean;
    /** Respect response `Cache-Control: private/no-store`. Default `true`. */
    readonly respectResponseCacheControl?: boolean;
    /** Cache responses with `Set-Cookie`. Default `false`. */
    readonly cacheSetCookie?: boolean;
    /** Cache responses to requests bearing `Authorization` or `Cookie` even when the response is not
     * explicitly `Cache-Control: public` (or `s-maxage`). Default `false`: a shared cache must not store a
     * personalized response (RFC 9111 §3.5), or it would be replayed to other users. Leave this off unless
     * the cached route is genuinely the same for every caller. */
    readonly cacheAuthenticated?: boolean;
    /** Response header for cache status. Default `"x-nifra-cache"`; set `false` to disable. */
    readonly cacheStatusHeader?: string | false;
}

export interface CacheStore {
    /** The live entry for `key`, or `undefined` if missing or hard-expired (`now >= expiresAt`). */
    get(key: string): StoredEntry | undefined | Promise<StoredEntry | undefined>;
    /** Store `entry` under `key`, indexed by `tags` for {@link CacheStore.invalidateTag}. */
    set(key: string, entry: StoredEntry, tags: readonly string[]): void | Promise<void>;
    delete(key: string): void | Promise<void>;
    /** Drop every entry carrying `tag`. */
    invalidateTag(tag: string): void | Promise<void>;
    clear(): void | Promise<void>;
}

export interface CacheStore {
    /** The cached entry for `key`, or `undefined` on a miss. */
    get(key: string): Promise<CachedResponse | undefined>;
    /** Store (or overwrite) the entry for `key`. */
    set(key: string, value: CachedResponse): Promise<void>;
    /** Drop `key` (on-demand revalidation / purge). A no-op if absent. */
    delete(key: string): Promise<void>;
}

