export interface ScheduledController {
    /** Epoch ms the run was scheduled for. */
    readonly scheduledTime: number;
    /** The matching cron expression from `wrangler.toml` `[triggers]`. */
    readonly cron: string;
    /** Tell the platform not to retry this run on failure. */
    noRetry(): void;
}

export type ScheduledHandler<Env = unknown> = (controller: ScheduledController, context: {
    readonly env: Env;
    waitUntil(promise: Promise<unknown>): void;
}) => MaybePromise<void>;

export interface Scheduler {
    /** Register a job. Throws `CronError` now (not at fire time) on a bad expression or duplicate name. */
    add(name: string, expression: string, handler: CronHandler): Scheduler;
    /** Begin checking on an interval (default 15s — well under a minute, so no minute is missed). */
    start(checkIntervalMs?: number): void;
    /** Stop checking. In-flight handlers are left to finish (graceful). */
    stop(): void;
    /** Run every job DUE at `now` that hasn't fired this minute. Exposed for tests + custom drivers. */
    tick(now?: Date): void;
    /** Fire a job immediately by name, off-schedule (e.g. a manual admin trigger). No-op if unknown. */
    runNow(name: string): void;
    /** Registered job names, in insertion order. */
    readonly jobNames: readonly string[];
}

export interface SchedulerOptions {
    /** Called when a job handler throws/rejects. Default: `console.error`. A throwing onError is swallowed. */
    readonly onError?: (error: unknown, jobName: string) => void;
    /** Injectable clock (tests). Default `() => new Date()`. */
    readonly now?: () => Date;
}

export interface SchemaReflection {
    /** The Standard Schema validator, when the value implements Standard Schema v1. */
    readonly standard: StandardSchemaV1 | undefined;
    /** Raw JSON Schema metadata, when the value exposes it or is itself a raw JSON Schema. */
    readonly jsonSchema: JsonSchema | undefined;
    /** Top-level object fields, or `undefined` when the JSON Schema is absent/non-object. */
    readonly fields: readonly ReflectedSchemaField[] | undefined;
}

export interface SchemaSnapshot {
    readonly jsonSchema?: JsonSchema;
    readonly fields?: readonly ReflectedSchemaField[];
}

export interface ScoredExample extends Example {
    readonly score: number;
}

export interface ScoredSection extends DocSection {
    readonly score: number;
}

export interface ScoredType extends TypeEntry {
    readonly score: number;
}

export interface ScriptDescriptor {
    /** The script's `type` attribute. Default `"application/ld+json"`. */
    readonly type?: string;
    /** The script body (e.g. a `JSON.stringify`'d JSON-LD object). Escaped for safe `<script>` embedding. */
    readonly content: string;
}

export interface ScssPluginOptions {
    /** Inject the compiler (default: the `sass` optional peer, loaded lazily). Pass `sass-embedded` or a stub. */
    readonly compiler?: SassCompiler;
    /** Output style handed to Sass. Default `"expanded"` (Bun minifies the final CSS bundle anyway). */
    readonly style?: "expanded" | "compressed";
    /** Extra import search paths for `@use`/`@import`, in addition to the source file's own directory. */
    readonly loadPaths?: readonly string[];
}

export interface SealedEffectLedger {
    readonly method: string;
    /** The registered route pattern (`/users/:id`) — never the concrete request URL. */
    readonly path: string;
    readonly entries: readonly EffectEntry[];
    /** The route's declared capability tokens — the runtime-enforcement view: recorded ⊆ declared is
     * guaranteed by the beacon, and `declared` minus the recorded ids is the unused declaration set. */
    readonly declared: readonly string[];
    /** Present when the ledger was created with `chain: true`. */
    readonly chain?: EffectChain;
}

