export interface SecurityHeadersOptions {
    /** `Strict-Transport-Security`. Off by default — opt in once you're sure you're HTTPS-only. */
    readonly hsts?: {
        readonly maxAge: number;
        readonly includeSubDomains?: boolean;
        readonly preload?: boolean;
    };
    /** `Content-Security-Policy` value. Off by default (app-specific). */
    readonly contentSecurityPolicy?: string;
    /** `X-Frame-Options`. Default `"DENY"`. */
    readonly frameOptions?: "DENY" | "SAMEORIGIN";
    /** `Referrer-Policy`. Default `"no-referrer"`. */
    readonly referrerPolicy?: string;
}

export interface SelfHostedLoaderOptions {
    /** Path/URL where `createImageHandler` (`@nifrajs/image/server`) is mounted, e.g. `"/_image"`. */
    readonly endpoint: string;
    /**
     * HMAC secret for **signed URLs**. When set, each URL gets a stable `&s=` signature and the handler
     * must be configured with the SAME `signing.secret` — it then rejects any unsigned/forged `(src, w, q)`,
     * shutting down resize-bombing. ⚠️ The signer holds the secret, so a loader created with it is
     * **server-only** — inject it like a session secret (from `env`), never import this config into a
     * route/client module. Signatures are stable (no expiry), so SSR-signed URLs hydrate + cache identically.
     */
    readonly secret?: string;
}

export declare function serializeResponse(response: Response, options?: {
    readonly maxBytes?: number;
}): Promise<StoredResponse>;

export interface ServeDatabaseAsMcpOptions {
    /**
     * REQUIRED allowlist of tables the MCP surface may see. `list_tables`/`describe_table` are
     * restricted to it and `run_query` plans are verified against it. Empty array → construction
     * throws; expose nothing by accident, ever.
     */
    readonly tables: readonly string[];
    /** Enable the `run_query` tool. Omitted → schema tools only. */
    readonly runQuery?: RunQueryOptions;
    /** MCP server identity (defaults: name `nifra-db`, version `1.0.0`). */
    readonly name?: string;
    readonly version?: string;
    /**
     * Set `PRAGMA query_only = ON` on the connection at construction (default true). Disable ONLY
     * when the same connection must also serve writes elsewhere in the app — with it disabled,
     * `run_query` still gates on SELECT/WITH + plan verification, but the engine-level guarantee is
     * yours to provide (e.g. open a second, read-only connection for the MCP mount — preferred).
     */
    readonly enforceQueryOnly?: boolean;
}

export interface ServeOptions {
    readonly port: number;
    readonly hostname?: string;
    /**
     * Protocol used when the adapter constructs `Request.url`.
     *
     * `@nifrajs/node` creates a plain Node `http` server, so the safe default is `"http"`. Deployments behind
     * TLS termination can set `"https"` (or a trusted infra-aware function) so app code that reads
     * `request.url` sees the public scheme. Forwarded headers are not trusted implicitly.
     */
    readonly protocol?: RequestProtocolOption;
    /**
     * Install SIGTERM/SIGINT handlers that call `stop()` for a graceful drain on
     * `docker stop` / Ctrl-C. Off by default — taking over process signals is opt-in,
     * mirroring nifra's Bun `listen({ gracefulSignals })`.
     *
     * The app-level request timeout (`server({ requestTimeoutMs })` → 503) and body cap
     * are *not* set here — they live inside `app.fetch`, so they already apply through
     * this adapter. Slow-client protection is Node's built-in `requestTimeout` (300s) /
     * `headersTimeout` (60s) defaults.
     */
    readonly signals?: boolean;
    /**
     * Serve static files from disk for matching GET/HEAD requests *before* the app runs — non-matching
     * requests fall through to `app.fetch` with the node-direct fast path intact (no perf regression on
     * SSR/API routes). Replaces the hand-rolled `/assets/*` reader in self-hosted entries.
     */
    readonly static?: ServeStaticOptions;
}

export interface ServePublicDirOptions {
    /** Absolute path of the directory to serve. */
    readonly dir: string;
    /** URL prefix whose files are content-hashed and may be cached immutably (default `"/assets/"`). */
    readonly hashedPrefix?: string;
    readonly cache?: PublicDirCache;
}

